422→    void searchRemoteMessagesSynchronous(String acctUuid, long folderId, String query, Set<Flag> requiredFlags,
423→            Set<Flag> forbiddenFlags, MessagingListener listener) {
424→
425→        Account account = preferences.getAccount(acctUuid);
426→
427→        if (listener != null) {
428→            listener.remoteSearchStarted(folderId);
429→        }
430→
431→        List<String> extraResults = new ArrayList<>();
432→        try {
433→            LocalStore localStore = localStoreProvider.getInstance(account);
434→
435→            LocalFolder localFolder = localStore.getFolder(folderId);
436→            if (!localFolder.exists()) {
